<!-- 功能说明
管理员个人中心页
管理端个人中心页面，展示管理员基础信息（账号、角色、登录时间），提供密码修改入口、登录日志查看、退出登录功能，
核心对接管理员信息、登录日志接口，确保权限控制与操作便捷性。 -->


<template>
  <view class="admin-center-container">
    <!-- 管理员信息卡片 -->
    <view class="admin-info-card">
      <image src="/static/images/admin-avatar.png" class="admin-avatar"></image>
      <view class="admin-base-info">
        <text class="admin-name">{{adminInfo.username || '管理员'}}</text>
        <view class="admin-role">
          <text class="role-label">角色：</text>
          <text class="role-value" :class="adminInfo.role === 'ADMIN' ? 'role-admin' : 'role-cs'">
            {{adminInfo.role === 'ADMIN' ? '超级管理员' : '客服人员'}}
          </text>
        </view>
        <view class="login-time">
          <text class="time-label">最后登录：</text>
          <text class="time-value">{{formatTime(adminInfo.lastLoginTime) || '暂无记录'}}</text>
        </view>
      </view>
    </view>

    <!-- 功能入口 -->
    <view class="function-section">
      <view class="function-list">
        <view class="function-item" @click="goToModifyPassword">
          <image src="/static/images/icon-password.png" class="function-icon"></image>
          <text class="function-name">修改密码</text>
          <image src="/static/images/icon-arrow-right.png" class="arrow-icon"></image>
        </view>
        <view class="function-item" @click="goToLoginLog">
          <image src="/static/images/icon-log.png" class="function-icon"></image>
          <text class="function-name">登录日志</text>
          <image src="/static/images/icon-arrow-right.png" class="arrow-icon"></image>
        </view>
        <view class="function-item" @click="logout">
          <image src="/static/images/icon-logout.png" class="function-icon"></image>
          <text class="function-name">退出登录</text>
          <image src="/static/images/icon-arrow-right.png" class="arrow-icon"></image>
        </view>
      </view>
    </view>

    <!-- 系统信息 -->
    <view class="system-info">
      <text class="system-text">系统版本：v1.0.0</text>
      <text class="system-text">更新时间：2025-01-01</text>
    </view>
  </view>
</template>
<script setup>
import { ref } from 'vue';
import { onLoad } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const adminInfo = ref({
  username: '',
  role: '',
  lastLoginTime: ''
});

// 页面加载获取管理员信息
onLoad(() => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userStore.userInfo.role)) {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getAdminInfo();
});

// 获取管理员信息
const getAdminInfo = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/admin/user/info',
      method: 'GET'
    });
    if (res.success) {
      adminInfo.value = res.data;
    }
  } catch (error) {
    uni.showToast({ title: '信息加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};

// 跳转密码修改页
const goToModifyPassword = () => {
  uni.navigateTo({ url: '/pages/admin/password/modify' });
};

// 跳转登录日志页（预留）
const goToLoginLog = () => {
  uni.showToast({ title: '登录日志功能暂未开放', icon: 'none' });
};

// 退出登录
const logout = () => {
  uni.showModal({
    title: '提示',
    content: '确定要退出登录吗？',
    success: (res) => {
      if (res.confirm) {
        userStore.logout();
        uni.navigateTo({ url: '/pages/admin/login' });
      }
    }
  });
};
</script>

